DELETE FROM "camonairflow"."geo_data"."geo_cities" as d WHERE EXISTS (SELECT 1 FROM "camonairflow"."geo_data_staging"."geo_cities" as s WHERE d."city_id" = s."city_id");
INSERT INTO "camonairflow"."geo_data"."geo_cities"("city_id", "city", "latitude", "longitude", "country", "country_code", "region", "region_code", "continent", "_dlt_load_id", "_dlt_id")              SELECT "city_id", "city", "latitude", "longitude", "country", "country_code", "region", "region_code", "continent", "_dlt_load_id", "_dlt_id"                 FROM (                     SELECT ROW_NUMBER() OVER (partition BY "city_id" ORDER BY (SELECT NULL)) AS _dlt_dedup_rn, "city_id", "city", "latitude", "longitude", "country", "country_code", "region", "region_code", "continent", "_dlt_load_id", "_dlt_id"                     FROM "camonairflow"."geo_data_staging"."geo_cities"                 ) AS _dlt_dedup_numbered WHERE _dlt_dedup_rn = 1 AND (1 = 1)         ;